//  KONFIGURASI DATABASE – sesuaikan dengan setting Laragon
// ═══════════════════════════════════════════════════════════
define('DB_HOST', 'localhost');
define('DB_USER', 'root');        // default Laragon
define('DB_PASS', '');            // default Laragon (kosong)
define('DB_NAME', 'lost_found_db');
define('DB_PORT', 3306);

function getDB(): PDO {
    static $pdo = null;
    if ($pdo === null) {
        $dsn = 'mysql:host='.DB_HOST.';port='.DB_PORT.';dbname='.DB_NAME.';charset=utf8mb4';
        $pdo = new PDO($dsn, DB_USER, DB_PASS, [
            PDO::ATTR_ERRMODE            => PDO::ERRMODE_EXCEPTION,
            PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
        ]);
    }
    return $pdo;
}

$LOGO_URI = "data:image/png;base64,";


// ─── Helper functions ────────────────────────────────────────
function fmtDate($d){$m=['01'=>'Jan','02'=>'Feb','03'=>'Mar','04'=>'Apr','05'=>'Mei','06'=>'Jun','07'=>'Jul','08'=>'Agu','09'=>'Sep','10'=>'Okt','11'=>'Nov','12'=>'Des'];[$y,$mo,$dy]=explode('-',$d);return "$dy {$m[$mo]} $y";}
function timeAgo($ts){$diff=(time()-strtotime($ts))/60;if($diff<60)return (int)$diff.' mnt lalu';$h=(int)($diff/60);if($h<24)return $h.' jam lalu';return (int)($h/24).' hari lalu';}
function stLabel($s){return['open'=>'Aktif','matched'=>'Sudah Ditemukan','closed'=>'Selesai'][$s]??$s;}
function stClass($s){return['open'=>'st-open','matched'=>'st-matched','closed'=>'st-closed'][$s]??'';}
function tpLabel($t){return $t==='lost'?'Hilang':'Ditemukan';}
function tpClass($t){return $t==='lost'?'tp-lost':'tp-found';}
function h($s){return htmlspecialchars($s,ENT_QUOTES,'UTF-8');}
function getUser(){return $_SESSION['user']??null;}

$categories = ['Elektronik','Dompet / Tas','Kunci','Dokumen','Pakaian','Perhiasan','Lainnya'];
$errors = [];
$page = $_GET['page'] ?? 'list';

// ─── LOGIN ───────────────────────────────────────────────────
if (isset($_POST['action']) && $_POST['action'] === 'login') {
    $username = trim($_POST['username'] ?? '');
    $password = trim($_POST['password'] ?? '');
    try {
        $stmt = getDB()->prepare('SELECT * FROM users WHERE username = ? LIMIT 1');
        $stmt->execute([$username]);
        $row = $stmt->fetch();
        if ($row && password_verify($password, $row['password'])) {
            $u = ['id'=>$row['id'],'username'=>$row['username'],'role'=>$row['role'],'name'=>$row['name'],'avatar'=>$row['avatar']];
            $_SESSION['user'] = $u;
            header('Location: ?page='.($u['role']==='admin'?'dashboard':'list').'&toast=login_ok'); exit;
        } else {
            $errors['login'] = 'Username atau password salah';
        }
    } catch (PDOException $e) {
        $errors['login'] = 'Koneksi database gagal: '.$e->getMessage();
    }
}

// ─── LOGOUT ──────────────────────────────────────────────────
if (isset($_GET['logout'])) { session_destroy(); header('Location: ?'); exit; }

// ─── TAMBAH LAPORAN ─────────────────────────────────────────
if (isset($_POST['action']) && in_array($_POST['action'], ['report_lost','report_found'])) {
    $u = getUser(); if (!$u) { header('Location: ?'); exit; }
    $type        = $_POST['action']==='report_lost' ? 'lost' : 'found';
    $title       = trim($_POST['title']       ?? '');
    $location    = trim($_POST['location']    ?? '');
    $date        = trim($_POST['date']        ?? '');
    $description = trim($_POST['description'] ?? '');
    $category    = trim($_POST['category']    ?? '');
    $photo       = null;
    if (!$title       || strlen($title)<3)       $errors['title']       = 'Judul wajib diisi (min 3 karakter)';
    if (!$location    || strlen($location)<3)    $errors['location']    = 'Lokasi wajib diisi (min 3 karakter)';
    if (!$date)                                   $errors['date']        = 'Tanggal wajib diisi';
    elseif (strtotime($date) > time())            $errors['date']        = 'Tidak boleh masa depan';
    if (!$description || strlen($description)<10) $errors['description'] = 'Deskripsi wajib diisi (min 10 karakter)';
    if (isset($_FILES['photo']) && $_FILES['photo']['error'] === UPLOAD_ERR_OK) {
        if ($_FILES['photo']['size'] > 5*1024*1024) $errors['photo'] = 'Foto max 5MB';
        else {
            $imgData = base64_encode(file_get_contents($_FILES['photo']['tmp_name']));
            $mime    = mime_content_type($_FILES['photo']['tmp_name']);
            $photo   = "data:{$mime};base64,{$imgData}";
        }
    }
    if (empty($errors)) {
        $stmt = getDB()->prepare(
            'INSERT INTO reports (type,title,category,location,date,description,photo,status,reporter,user_id)
             VALUES (?,?,?,?,?,?,?,\'open\',?,?)'
        );
        $stmt->execute([$type,$title,$category,$location,$date,$description,$photo,$u['name'],$u['id']]);
        header('Location: ?page=history&toast=report_ok'); exit;
    }
}

// ─── UBAH STATUS ─────────────────────────────────────────────
if (isset($_POST['action']) && $_POST['action'] === 'change_status') {
    $u = getUser();
    if ($u) {
        $rid = (int)$_POST['report_id'];
        $ns  = $_POST['new_status'];
        if ($u['role'] === 'admin') {
            $stmt = getDB()->prepare('UPDATE reports SET status=? WHERE id=?');
            $stmt->execute([$ns, $rid]);
        } else {
            $stmt = getDB()->prepare('UPDATE reports SET status=? WHERE id=? AND user_id=?');
            $stmt->execute([$ns, $rid, $u['id']]);
        }
        header('Location: ?page='.$page.'&toast=status_ok'); exit;
    }
}

// ─── CHAT: API ENDPOINT (JSON) ───────────────────────────────
if (isset($_GET['chat_api'])) {
    header('Content-Type: application/json');
    $u = getUser();
    if (!$u) { echo json_encode(['error'=>'unauthenticated']); exit; }
    $db = getDB();

    $action = $_GET['chat_api'];

    // Kirim pesan
    if ($action === 'send' && isset($_POST['msg'])) {
        $msg = trim($_POST['msg']);
        if (strlen($msg) === 0 || strlen($msg) > 2000) { echo json_encode(['error'=>'invalid']); exit; }
        if ($u['role'] === 'admin') {
            // Admin kirim ke user tertentu
            $roomUserId = (int)($_POST['room_user_id'] ?? 0);
            if (!$roomUserId) { echo json_encode(['error'=>'no room']); exit; }
            $stmt = $db->prepare('INSERT INTO chat_messages (sender_id,receiver_id,room_user_id,message) VALUES (?,?,?,?)');
            $stmt->execute([$u['id'], $roomUserId, $roomUserId, $msg]);
        } else {
            // User biasa kirim ke admin (ambil admin pertama)
            $admin = $db->query('SELECT id FROM users WHERE role="admin" LIMIT 1')->fetch();
            if (!$admin) { echo json_encode(['error'=>'no admin']); exit; }
            $stmt = $db->prepare('INSERT INTO chat_messages (sender_id,receiver_id,room_user_id,message) VALUES (?,?,?,?)');
            $stmt->execute([$u['id'], $admin['id'], $u['id'], $msg]);
        }
        echo json_encode(['ok'=>true, 'id'=>$db->lastInsertId()]); exit;
    }

    // Ambil pesan
    if ($action === 'fetch') {
        $since = (int)($_GET['since'] ?? 0);
        if ($u['role'] === 'admin') {
            $roomUserId = (int)($_GET['room_user_id'] ?? 0);
            if (!$roomUserId) { echo json_encode(['msgs'=>[], 'unread'=>[]]); exit; }
            // Tandai terbaca
            $db->prepare('UPDATE chat_messages SET is_read=1 WHERE room_user_id=? AND receiver_id=? AND is_read=0')
               ->execute([$roomUserId, $u['id']]);
            $stmt = $db->prepare('SELECT m.*,u.name sender_name,u.avatar sender_avatar,u.role sender_role FROM chat_messages m JOIN users u ON u.id=m.sender_id WHERE m.room_user_id=? AND m.id>? ORDER BY m.created_at ASC');
            $stmt->execute([$roomUserId, $since]);
        } else {
            // Tandai terbaca dari admin
            $db->prepare('UPDATE chat_messages SET is_read=1 WHERE room_user_id=? AND receiver_id=? AND is_read=0')
               ->execute([$u['id'], $u['id']]);
            $stmt = $db->prepare('SELECT m.*,u.name sender_name,u.avatar sender_avatar,u.role sender_role FROM chat_messages m JOIN users u ON u.id=m.sender_id WHERE m.room_user_id=? AND m.id>? ORDER BY m.created_at ASC');
            $stmt->execute([$u['id'], $since]);
        }
        $msgs = $stmt->fetchAll();
        // Badge: total unread rooms (untuk admin)
        $unread = [];
        if ($u['role'] === 'admin') {
            $rows = $db->prepare('SELECT room_user_id, COUNT(*) cnt FROM chat_messages WHERE receiver_id=? AND is_read=0 GROUP BY room_user_id');
            $rows->execute([$u['id']]);
            foreach ($rows->fetchAll() as $r) $unread[$r['room_user_id']] = (int)$r['cnt'];
        } else {
            $row = $db->prepare('SELECT COUNT(*) cnt FROM chat_messages WHERE room_user_id=? AND receiver_id=? AND is_read=0');
            $row->execute([$u['id'], $u['id']]);
            $unread = (int)$row->fetch()['cnt'];
        }
        echo json_encode(['msgs'=>$msgs, 'unread'=>$unread]); exit;
    }

    // Daftar room (khusus admin)
    if ($action === 'rooms' && $u['role'] === 'admin') {
        $stmt = $db->query('
            SELECT u.id, u.name, u.avatar,
                   MAX(m.created_at) last_msg_at,
                   LEFT(( SELECT message FROM chat_messages WHERE room_user_id=u.id ORDER BY created_at DESC LIMIT 1 ),60) last_msg,
                   (SELECT COUNT(*) FROM chat_messages WHERE room_user_id=u.id AND receiver_id='.$u['id'].' AND is_read=0) unread
            FROM users u
            JOIN chat_messages m ON m.room_user_id = u.id
            WHERE u.role = "user"
            GROUP BY u.id
            ORDER BY last_msg_at DESC
        ');
        echo json_encode(['rooms' => $stmt->fetchAll()]); exit;
    }

    echo json_encode(['error'=>'unknown action']); exit;
}

// ─── AMBIL DATA ──────────────────────────────────────────────
$user    = getUser();
$search  = trim($_GET['search'] ?? '');
$fType   = $_GET['type']   ?? 'all';
$fStatus = $_GET['status'] ?? 'all';
$fFrom   = $_GET['from']   ?? '';
$fTo     = $_GET['to']     ?? '';

function fetchReports(string $search, string $fType, string $fStatus, string $fFrom, string $fTo): array {
    $sql    = 'SELECT * FROM reports WHERE 1=1';
    $params = [];
    if ($fType   !== 'all') { $sql .= ' AND type=?';   $params[] = $fType; }
    if ($fStatus !== 'all') { $sql .= ' AND status=?'; $params[] = $fStatus; }
    if ($search) {
        $sql .= ' AND (title LIKE ? OR location LIKE ? OR category LIKE ? OR reporter LIKE ?)';
        $like = '%'.$search.'%';
        array_push($params, $like, $like, $like, $like);
    }
    if ($fFrom) { $sql .= ' AND date >= ?'; $params[] = $fFrom; }
    if ($fTo)   { $sql .= ' AND date <= ?'; $params[] = $fTo; }
    $sql .= ' ORDER BY created_at DESC';
    $stmt = getDB()->prepare($sql);
    $stmt->execute($params);
    // Normalize keys to match old array keys (userId, createdAt)
    return array_map(function($r){
        $r['userId']    = $r['user_id'];
        $r['createdAt'] = $r['created_at'];
        return $r;
    }, $stmt->fetchAll());
}

function fetchAllReports(): array {
    $stmt = getDB()->query('SELECT * FROM reports ORDER BY created_at DESC');
    return array_map(function($r){
        $r['userId']    = $r['user_id'];
        $r['createdAt'] = $r['created_at'];
        return $r;
    }, $stmt->fetchAll());
}

try {
    $filtered = fetchReports($search, $fType, $fStatus, $fFrom, $fTo);
    $reports  = fetchAllReports();
} catch (PDOException $e) {
    // Jika DB belum dibuat, tampilkan pesan setup
    die('<pre style="font-family:monospace;padding:2em;color:#c00">
<b>❌ Koneksi Database Gagal</b>

Error: '.$e->getMessage().'

Langkah setup:
1. Buka phpMyAdmin di http://localhost/phpmyadmin
2. Import file  lost_found_setup.sql
3. Refresh halaman ini

Konfigurasi saat ini:
  Host : '.DB_HOST.'
  User : '.DB_USER.'
  DB   : '.DB_NAME.'
</pre>');
}

$total    = count($reports);
$tLost    = count(array_filter($reports, fn($r) => $r['type']==='lost'));
$tFound   = count(array_filter($reports, fn($r) => $r['type']==='found'));
$tOpen    = count(array_filter($reports, fn($r) => $r['status']==='open'));
$tMatched = count(array_filter($reports, fn($r) => $r['status']==='matched'));
$tClosed  = count(array_filter($reports, fn($r) => $r['status']==='closed'));
?>
