</div>

<script>
(function(){
  const IS_ADMIN = <?=$user['role']==='admin'?'true':'false'?>;
  const MY_ID    = <?=(int)$user['id']?>;
  const MY_NAME  = <?=json_encode($user['name'])?>;
  const MY_AVATAR= <?=json_encode($user['avatar'])?>;
  const API      = '?chat_api=';

  let isOpen       = false;
  let currentRoom  = null; // room_user_id
  let lastMsgId    = 0;
  let pollTimer    = null;
  let totalUnread  = 0;
  let roomUnread   = {}; // admin: {room_user_id: count}

  /* ── toggle open/close ── */
  window.chatToggle = function(){
    isOpen = !isOpen;
    document.getElementById('chat-win').classList.toggle('open', isOpen);
    if(isOpen){
      if(!IS_ADMIN){ startPoll(); scrollBottom(); }
      else { loadRooms(); }
    } else { stopPoll(); }
  };
  window.chatClose = function(){ isOpen=false; document.getElementById('chat-win').classList.remove('open'); stopPoll(); };
  window.chatBack  = function(){
    if(!IS_ADMIN) return;
    currentRoom = null; lastMsgId = 0; stopPoll();
    document.getElementById('chat-rooms-panel').style.display = '';
    document.getElementById('chat-msgs-panel').style.display = 'none';
    document.getElementById('chat-back').style.display = 'none';
    document.getElementById('chat-header-title').innerHTML = 'Chat Pengguna <span class="chat-24">24 jam</span>';
    document.getElementById('chat-header-sub').textContent = 'Pilih pengguna untuk membalas';
    document.getElementById('chat-header-av').textContent = '💬';
    document.getElementById('chat-msgs').innerHTML = '';
    loadRooms();
  };

  /* ── Rooms (admin) ── */
  function loadRooms(){
    fetch(API+'rooms').then(r=>r.json()).then(data=>{
      const el = document.getElementById('chat-rooms-list');
      if(!data.rooms || data.rooms.length===0){
        el.innerHTML = '<div class="chat-rooms-empty">💬 Belum ada percakapan masuk</div>';
        return;
      }
      el.innerHTML = data.rooms.map(r=>`
        <div class="chat-room-item" onclick="openRoom(${r.id},${JSON.stringify(r.name)},${JSON.stringify(r.avatar)})">
          <div class="cr-av">${h(r.avatar)}</div>
          <div class="cr-info">
            <div class="cr-name">${h(r.name)}</div>
            <div class="cr-last">${h(r.last_msg||'')}</div>
          </div>
          ${+r.unread>0?`<div class="cr-badge">${r.unread}</div>`:''}
        </div>
      `).join('');
    });
  }

  window.openRoom = function(userId, userName, userAvatar){
    currentRoom = userId; lastMsgId = 0;
    document.getElementById('chat-rooms-panel').style.display = 'none';
    document.getElementById('chat-msgs-panel').style.display = 'flex';
    document.getElementById('chat-back').style.display = '';
    document.getElementById('chat-header-av').textContent = userAvatar;
    document.getElementById('chat-header-title').innerHTML = h(userName) + ' <span class="chat-24">24 jam</span>';
    document.getElementById('chat-header-sub').textContent = 'Pengguna';
    document.getElementById('chat-msgs').innerHTML = '<div style="text-align:center;color:var(--txt3);font-size:12px;padding:20px 0;">⏳ Memuat pesan...</div>';
    startPoll();
  };

  /* ── Send ── */
  window.chatSend = function(){
    const ta = document.getElementById('chat-textarea');
    const msg = ta.value.trim();
    if(!msg) return;
    ta.value = ''; ta.style.height = 'auto';

    const body = new FormData();
    body.append('msg', msg);
    if(IS_ADMIN && currentRoom) body.append('room_user_id', currentRoom);

    fetch(API+'send', {method:'POST', body})
      .then(r=>r.json()).then(d=>{ if(d.ok) fetchMsgs(); });
  };

  /* ── Poll ── */
  function startPoll(){
    stopPoll();
    fetchMsgs();
    pollTimer = setInterval(fetchMsgs, 3000);
  }
  function stopPoll(){ if(pollTimer){clearInterval(pollTimer);pollTimer=null;} }

  function fetchMsgs(){
    let url = API+'fetch&since='+lastMsgId;
    if(IS_ADMIN && currentRoom) url += '&room_user_id='+currentRoom;
    else if(IS_ADMIN) return; // admin belum pilih room

    fetch(url).then(r=>r.json()).then(data=>{
      // Update unread badge
      if(IS_ADMIN){
        roomUnread = data.unread || {};
        let tot = Object.values(roomUnread).reduce((a,b)=>a+b,0);
        setBadge(tot);
      } else {
        setBadge(data.unread||0);
      }

      if(!data.msgs || data.msgs.length===0) return;
      const container = document.getElementById('chat-msgs');

      // Clear placeholder
      const ph = container.querySelector('[style*="padding:20px"]');
      if(ph) ph.remove();

      data.msgs.forEach(m=>{
        if(m.id <= lastMsgId) return;
        lastMsgId = Math.max(lastMsgId, +m.id);
        const isMine = (+m.sender_id === MY_ID);
        const timeStr = new Date(m.created_at).toLocaleTimeString('id-ID',{hour:'2-digit',minute:'2-digit'});
        const div = document.createElement('div');
        div.className = 'msg-row' + (isMine?' mine':'');
        div.innerHTML = `
          <div class="msg-av">${h(m.sender_avatar)}</div>
          <div class="msg-wrap">
            <div class="msg-bubble">${escHtml(m.message)}</div>
            <div class="msg-time">${timeStr}</div>
          </div>`;
        container.appendChild(div);
      });
      scrollBottom();
    });
  }

  /* ── Badge ── */
  function setBadge(n){
    totalUnread = n;
    const el = document.getElementById('fab-badge');
    if(n>0){ el.textContent=n>99?'99+':n; el.style.display='flex'; }
    else { el.style.display='none'; }
  }

  /* ── Helpers ── */
  function scrollBottom(){
    const el = document.getElementById('chat-msgs');
    el.scrollTop = el.scrollHeight;
  }
  function h(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
  function escHtml(s){
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
  }

  /* ── Auto-poll saat window terbuka meskipun chat tertutup (untuk badge) ── */
  if(!IS_ADMIN){
    setInterval(()=>{
      fetch(API+'fetch&since=9999999').then(r=>r.json()).then(d=>setBadge(d.unread||0));
    }, 8000);
  } else {
    setInterval(()=>{
      fetch(API+'rooms').then(r=>r.json()).then(data=>{
        if(!data.rooms) return;
        let tot = data.rooms.reduce((a,r)=>a+(+r.unread),0);
        setBadge(tot);
      });
    }, 8000);
  }
})();
</script>
<?php endif; ?>
</body>
</html>

